package be.schaubroeck.lpb.rkm.rekenmotor.factory;

import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelManager;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorResultaatHandler;
import be.schaubroeck.lpb.rkm.rekenmotor.PreBerekeningInterpreter;
import be.schaubroeck.lpb.rkm.rekenmotor.RegulManagerFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenChainFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategy;
import be.schaubroeck.lpb.rkm.rekenmotor.results.ResultaatHandler;

public class RekenStrategyImp implements RekenMotorStrategy {

    private RekenChainFactory rekenChainFactory;
    private ResultaatHandler resultaatHandler;
    private RegulManagerFactory regulManagerFactory;
    private PreBerekeningInterpreter preBerekeningInterpreter;
    private ArtikelManager artikelManager;
    private ArtikelMotorResultaatHandler artikelMotorResultaatHandler;

    @Override
    public RekenChainFactory getRekenChainFactory() {
        return rekenChainFactory;
    }

    @Override
    public void setRekenChainFactory(RekenChainFactory rekenChainFactory) {
        this.rekenChainFactory = rekenChainFactory;
    }

    @Override
    public ResultaatHandler getResultaatHandler() {
        return resultaatHandler;
    }

    @Override
    public void setResultaatHandler(ResultaatHandler resultaatHandler) {
        this.resultaatHandler = resultaatHandler;
    }

    @Override
    public RegulManagerFactory getRegulManagerFactory() {
        return regulManagerFactory;
    }

    @Override
    public void setRegulManagerFactory(RegulManagerFactory regulManagerFactory) {
        this.regulManagerFactory = regulManagerFactory;
    }

    @Override
    public PreBerekeningInterpreter getPreBerekeningInterpreter() {
        return preBerekeningInterpreter;
    }

    @Override
    public void setPreBerekeningInterpreter(PreBerekeningInterpreter preBerekeningInterpreter) {
        this.preBerekeningInterpreter = preBerekeningInterpreter;
    }

    @Override
    public ArtikelManager getArtikelManager() {
        return artikelManager;
    }

    public void setArtikelManager(ArtikelManager artikelManager) {
        this.artikelManager = artikelManager;
    }

    @Override
    public ArtikelMotorResultaatHandler getArtikelMotorResultaatHandler() {
        return artikelMotorResultaatHandler;
    }

    public void setArtikelMotorResultaatHandler(ArtikelMotorResultaatHandler artikelMotorResultaatHandler) {
        this.artikelMotorResultaatHandler = artikelMotorResultaatHandler;
    }
}
